import { Routes, Route, Outlet } from 'react-router-dom';
import './App.css';
import 'react-toastify/dist/ReactToastify.css';
import { Home } from './Pages/Employer/Home';
import { Navbar } from './components/Navbar';
import { PostJob } from './Pages/Employer/PostJob';
import { AllJobs } from './Pages/Employer/AllJobs';
import { Login } from './components/Login/Login';
import { Register } from './components/Login/Register';
import { RecruiterDashboard } from './Pages/Recruiter/RecruiterDashboard';
import { CoordinatorDashboard } from './Pages/Coordinator/CoordinatorDashboard';
import { JobDetails } from './components/Home/JobDetails';
import { CandidateProfile } from './Pages/Recruiter/CandidateProfile';
import { ShortlistedCandidates } from './components/ShortlistedCandidates';
import { ShortlistedDetails } from './components/ShortlistedDetails';
import { ApplicationForm } from './Pages/Candidate/ApplicationForm';
import { AssignRecruiter } from './Pages/Coordinator/AssignRecruiter';
import { Footer } from './components/Footer';
import {AllPostedJobs} from './components/AllPostedJobs'
import { Dashboard } from './Pages/Dashboard';
import { useContext, useEffect } from 'react';
import { LoginContext } from './components/ContextProvider/Context';
import { UpdateJob } from './Pages/Employer/UpdateJob';
import { MyJobs } from './Pages/Candidate/MyJobs';
import { ValidateUser } from './components/ValidateUser';

function App() {

  const {loginData, setLoginData} = useContext(LoginContext)



  return (
    <div className="App">
      <Routes>
          <Route path='/' element={<Navbar />}> 
            <Route path='/' element={<Home />}/>
            <Route path='*' element={<Home />}/>
            <Route path='/login' element={<Login />}/>
            <Route path='/signup' element={<Register />}/>
            <Route path='/all-posted-jobs' element={<AllPostedJobs />}/>
            <Route path='/current-job/:id' element={<JobDetails />}/>

            {/* Employer routes */}
            <Route path='/post-job' element={<ValidateUser allowedRoles={['employer']}><PostJob /></ValidateUser>}/>
            <Route path='/all-jobs' element={<ValidateUser allowedRoles={['employer']}><AllJobs /></ValidateUser>}/>
            <Route path='/update-job/:id' element={<ValidateUser allowedRoles={['employer']}><UpdateJob /></ValidateUser>}/>

            {/* Candidate routes */}
            <Route path='/application-form/:id' element={<ValidateUser allowedRoles={['candidate']}><ApplicationForm /></ValidateUser>}/>
            <Route path='/my-jobs/' element={<ValidateUser allowedRoles={['candidate']}><MyJobs /></ValidateUser>}/>

            {/* Recruiter routes */}
            <Route path='/recruiter/review' element={<ValidateUser allowedRoles={['recruiter']}><RecruiterDashboard /></ValidateUser>}/>
            <Route path='/candidate/:id' element={<ValidateUser allowedRoles={['recruiter']}><CandidateProfile /></ValidateUser>}/>

            {/* Coordinator routes */}
            <Route path='/coordinator/review' element={<ValidateUser allowedRoles={['coordinator']}><CoordinatorDashboard /></ValidateUser>}/>
            <Route path='/assign-recruiter/:id' element={<ValidateUser allowedRoles={['coordinator']}><AssignRecruiter /></ValidateUser>}/>

            {/* Shared routes (employer + coordinator) */}
            <Route path='/shortlist' element={<ValidateUser allowedRoles={['employer', 'coordinator']}><ShortlistedCandidates /></ValidateUser>}/>
            <Route path='/shortlist/details/:candidate_id/:job_id' element={<ValidateUser allowedRoles={['employer', 'coordinator']}><ShortlistedDetails /></ValidateUser>}/>

            <Route path='/dash' element={<ValidateUser><Dashboard /></ValidateUser>}/>

          </Route>

      </Routes>

      <Footer />
    </div>
  );
}

export default App;
